CREATE TYPE "RequestStatus" AS ENUM ('CREATED','SENT_TO_SUPPLIER','RECEIVED_BY_SUPPLIER','ACCEPTED','REJECTED','INVOICE_UPLOADED','VALUED','DELIVERED','CLOSED');
CREATE TYPE "Priority" AS ENUM ('BAJA','MEDIA','ALTA','URGENTE');
CREATE TYPE "AttachmentType" AS ENUM ('INVOICE','REMITO','GENERAL');
CREATE TABLE "roles" ("id" SERIAL PRIMARY KEY,"name" TEXT NOT NULL UNIQUE);
CREATE TABLE "suppliers" ("id" SERIAL PRIMARY KEY,"name" TEXT NOT NULL,"cuit" TEXT,"email" TEXT,"phone" TEXT,"address" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "users" ("id" SERIAL PRIMARY KEY,"name" TEXT NOT NULL,"email" TEXT NOT NULL UNIQUE,"password" TEXT NOT NULL,"roleId" INTEGER NOT NULL REFERENCES "roles"("id"),"supplierId" INTEGER REFERENCES "suppliers"("id"),"active" BOOLEAN NOT NULL DEFAULT true,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "requests" ("id" SERIAL PRIMARY KEY,"code" TEXT NOT NULL UNIQUE,"requesterId" INTEGER NOT NULL REFERENCES "users"("id"),"authorizerId" INTEGER NOT NULL REFERENCES "users"("id"),"supplierId" INTEGER NOT NULL REFERENCES "suppliers"("id"),"area" TEXT NOT NULL,"observations" TEXT,"authorizedPickupPerson" TEXT NOT NULL,"priority" "Priority" NOT NULL DEFAULT 'MEDIA',"status" "RequestStatus" NOT NULL DEFAULT 'CREATED',"supplierObservations" TEXT,"valuedAmount" DECIMAL(12,2),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "request_items" ("id" SERIAL PRIMARY KEY,"requestId" INTEGER NOT NULL REFERENCES "requests"("id") ON DELETE CASCADE,"material" TEXT NOT NULL,"quantity" DECIMAL(12,2) NOT NULL,"unit" TEXT NOT NULL DEFAULT 'unidad');
CREATE TABLE "attachments" ("id" SERIAL PRIMARY KEY,"requestId" INTEGER REFERENCES "requests"("id") ON DELETE SET NULL,"uploadedById" INTEGER NOT NULL REFERENCES "users"("id"),"type" "AttachmentType" NOT NULL,"fileName" TEXT NOT NULL,"originalName" TEXT NOT NULL,"mimeType" TEXT NOT NULL,"size" INTEGER NOT NULL,"path" TEXT NOT NULL,"url" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "invoices" ("id" SERIAL PRIMARY KEY,"requestId" INTEGER NOT NULL UNIQUE REFERENCES "requests"("id"),"number" TEXT NOT NULL,"date" TIMESTAMP(3) NOT NULL,"amount" DECIMAL(12,2) NOT NULL,"observations" TEXT,"attachmentId" INTEGER REFERENCES "attachments"("id"),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "remitos" ("id" SERIAL PRIMARY KEY,"requestId" INTEGER NOT NULL UNIQUE REFERENCES "requests"("id"),"deliveryDate" TIMESTAMP(3) NOT NULL,"deliveredTo" TEXT NOT NULL,"observations" TEXT,"attachmentId" INTEGER REFERENCES "attachments"("id"),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "request_status_history" ("id" SERIAL PRIMARY KEY,"requestId" INTEGER NOT NULL REFERENCES "requests"("id") ON DELETE CASCADE,"status" "RequestStatus" NOT NULL,"comment" TEXT,"changedById" INTEGER NOT NULL REFERENCES "users"("id"),"changedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
